boot.widget:
// CSS link 与内容都放入 shadowRoot;补上原 body 选择器承担的根层排版
for (const href of ['https://cdn.jsdelivr.net/npm/normalize.css@8/normalize.css','https://cdn.jsdelivr.net/npm/font-awesome@4/css/font-awesome.min.css','https://cdn.jsdelivr.net/gh/mnjul/html-resume@71ffb26da44abb41dad40b64eb7a975ccc5dd247/style.css']) {
  const link = document.createElement('link'); link.rel = 'stylesheet'; link.href = href; shadowRoot.appendChild(link);
}
const shell = document.createElement('div'); shell.lang = data.lang ?? 'en';
shell.style.cssText = `width:${spec.width ?? 816}px;height:${spec.height ?? 1056}px;overflow:hidden;font-family:'Open Sans',sans-serif;font-weight:300;line-height:1.3;color:#444;hyphens:auto`;
shell.innerHTML = data.body_html; shadowRoot.appendChild(shell);

